const items = $input.all();
const results = [];

const TYPE_MAP = {
  world_news: 'political_event', geopolitics: 'political_event',
  technology: 'technology', ai: 'technology', biotech: 'technology',
  research: 'technology', science: 'technology',
  startups: 'company', venture_capital: 'company', business: 'company',
  marketing: 'company', sales: 'company', management: 'company',
  economics: 'economic_event', hiring: 'economic_event', consumer: 'economic_event',
  mergers_acquisitions: 'economic_event', esg: 'economic_event',
  regulation: 'government_body', law: 'government_body',
  cybersecurity: 'conflict_event',
  energy: 'commodity_flow',
  crypto: 'financial_instrument',
  supply_chain: 'supply_chain',
  psychology: 'social_movement',
};

function extractMentions(text) {
  const matches = text.match(/\b([A-Z][a-z]+(?: [A-Z][a-z]+){1,3})\b/g) || [];
  return [...new Set(matches)].slice(0, 4);
}

for (const item of items) {
  const a = item.json;
  if (!a || !a.title || !a.source) continue;

  const title = String(a.title).trim().substring(0, 200);
  const category = a.category || 'world_news';
  const source = a.source;
  const url = a.link || a.url || '';
  const published = a.pubDate || a.isoDate || new Date().toISOString();
  const causal_weight = typeof a.causal_weight === 'number' ? a.causal_weight : 0.3;
  const mechanism = a.mechanism || 'news_signal';

  const description = String(a.content || a.contentSnippet || a.summary || '')
    .replace(/<[^>]*>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .substring(0, 600);

  const entityType = TYPE_MAP[category] || 'political_event';

  const relationships = [{
    targetName: source,
    targetType: 'company',
    targetProperties: { domain: 'media', category },
    relation: 'cited_by',
    confidence: 0.9,
    causal_weight: 0.1,
    mechanism: 'media_attribution'
  }];

  const mentions = extractMentions(title + ' ' + description.substring(0, 200));
  for (const mention of mentions) {
    relationships.push({
      targetName: mention,
      targetType: 'person',
      relation: 'related_to',
      confidence: 0.4,
      causal_weight: causal_weight * 0.5,
      mechanism
    });
  }

  results.push({ json: {
    name: title,
    type: entityType,
    properties: { url, description: description.substring(0, 500), category, published },
    relationships,
    source,
    confidence: 0.7,
    causal_weight,
    mechanism
  }});
}

return results.length > 0 ? results : [{ json: null }];

const items = $input.all().filter(i => i.json !== null && i.json !== undefined);
const BATCH_SIZE = 25;
const batches = [];
for (let i = 0; i < items.length; i += BATCH_SIZE) {
  batches.push({ json: { batch: items.slice(i, i + BATCH_SIZE).map(x => x.json) } });
}
return batches.length > 0 ? batches : [{ json: { batch: [] } }];

