for (const item of items) {
  const d = item.json;
  if (d && d.error) {
    console.error('[Graph Batch Error]', JSON.stringify(d));
  } else {
    console.log('[Graph Batch OK] accepted=' + (d && d.accepted_count ? d.accepted_count : '?'));
  }
}
return items;
